const handleSearch = async () => {
  setLoading(true);
  setError("");

  try {
    if (!phone.trim()) {
      setError("Please enter a phone number");
      setLoading(false);
      return;
    }

    const allPatients = await getPatients();

    const matchedPatients = allPatients.filter((p) =>
      String(p.phone || "").includes(phone)
    );

    setPatients(matchedPatients);

    const allAppointments = await getAppointments();

    const matchedAppointments = allAppointments.filter((a) =>
      matchedPatients.some((p) => p.id === a.patient_id)
    );

    setAppointments(matchedAppointments);

    let allPrescriptions = [];

    try {
      allPrescriptions = await getPrescriptions();
    } catch (err) {
      console.log("Prescription API missing or failing:", err.message);
    }

    const matchedPrescriptions = allPrescriptions.filter((pr) =>
      matchedPatients.some((p) => p.id === pr.patient_id)
    );

    setPrescriptions(matchedPrescriptions);
  } catch (err) {
    console.error(err);
    setError("Backend error: check API routes or server");
  }

  setLoading(false);
};
